from typing import List, Tuple


class Solution:
    def expressiveWords(self, S: str, words: List[str]) -> List[str]:
        target_groups = self._groups(S)
        result: List[str] = []
        for word in words:
            if self._is_stretchy(target_groups, self._groups(word)):
                result.append(word)
        return result

    def _groups(self, s: str) -> List[Tuple[str, int]]:
        groups: List[Tuple[str, int]] = []
        i = 0
        n = len(s)
        while i < n:
            j = i
            while j < n and s[j] == s[i]:
                j += 1
            groups.append((s[i], j - i))
            i = j
        return groups

    def _is_stretchy(self, gS, gW) -> bool:
        if len(gS) != len(gW):
            return False
        for (sc, scount), (wc, wcount) in zip(gS, gW):
            if sc != wc:
                return False
            if scount < wcount:
                return False
            if scount != wcount and scount < 3:
                return False
        return True


# ---- brute oracle: simulate by checking count rule directly on raw strings via two pointers
def brute(S, words):
    def stretch(word):
        i = j = 0
        n, m = len(S), len(word)
        while i < n and j < m:
            if S[i] != word[j]:
                return False
            ci = i
            while ci < n and S[ci] == S[i]:
                ci += 1
            cj = j
            while cj < m and word[cj] == word[j]:
                cj += 1
            slen, wlen = ci - i, cj - j
            if slen < wlen:
                return False
            if slen != wlen and slen < 3:
                return False
            i, j = ci, cj
        return i == n and j == m
    return [w for w in words if stretch(w)]


if __name__ == "__main__":
    sol = Solution()
    # sample
    print(sol.expressiveWords("heeellooo", ["hello", "hi", "helo"]))  # ["hello"]
    # edges
    print(sol.expressiveWords("helloo", ["hello"]))    # [] grew o to 2 -> illegal
    print(sol.expressiveWords("hello", ["hello"]))      # ["hello"] exact match
    print(sol.expressiveWords("aaa", ["a", "aa", "aaa"]))  # ["a","aaa"]; "aa"->aaa grew to3 ok wait
    print(sol.expressiveWords("a", ["aaa"]))            # [] word longer
    print(sol.expressiveWords("abcd", ["abcd"]))        # ["abcd"]

    # random fuzz vs brute
    import random, string
    for _ in range(20000):
        S = "".join(random.choice("ab") for _ in range(random.randint(1, 8)))
        words = ["".join(random.choice("ab") for _ in range(random.randint(1, 8)))
                 for _ in range(random.randint(1, 4))]
        if sol.expressiveWords(S, words) != brute(S, words):
            print("MISMATCH", S, words, sol.expressiveWords(S, words), brute(S, words))
            break
    else:
        print("fuzz OK")
